from __future__ import annotations

import keyword
import os
from pathlib import Path
import shutil
import sys
from typing import Any, Callable, Dict, List, Optional

_tool_registry: Dict[str, Callable[..., Any]] = {}
_skill_registry: Dict[str, Dict[str, Any]] = {}
_RUNTIME_TOOL_MODULE = "chatdev_runtime_tools.py"

_INTERNAL_ROOT = Path(__file__).resolve().parents[1] / "_internal"
if _INTERNAL_ROOT.exists():
    internal_path = str(_INTERNAL_ROOT)
    if internal_path not in sys.path:
        sys.path.append(internal_path)


def _validate_identifier(name: str) -> None:
    if not name.isidentifier() or keyword.iskeyword(name):
        raise ValueError(
            f"Invalid name '{name}'. Use a valid Python identifier for tool/skill names."
        )

def _skills_root() -> Path:
    override = os.environ.get("CHATDEV_SKILLS_DIR")
    if override and override.strip():
        return Path(override).expanduser().resolve()
    return (Path.cwd() / ".agents" / "skills").resolve()


def _write_skill_md(*, name: str, description: str, instructions: Optional[str]) -> Path:
    root = _skills_root()
    skill_dir = root / name
    skill_dir.mkdir(parents=True, exist_ok=True)
    skill_file = skill_dir / "SKILL.md"
    body = instructions.strip() if isinstance(instructions, str) and instructions.strip() else (
        f"# {name}\n\n{description}\n"
    )
    content = "\n".join(
        [
            "---",
            f"name: {name}",
            f"description: {description}",
            "---",
            "",
            body,
            "",
        ]
    )
    skill_file.write_text(content, encoding="utf-8")
    return skill_file


def _runtime_tools_root() -> Path:
    # Writable runtime folder that can host a full function_calling tree.
    # Users can override if needed.
    override = os.environ.get("CHATDEV_RUNTIME_TOOLS_DIR")
    if override and override.strip():
        return Path(override).expanduser().resolve()
    return (Path.cwd() / ".chatdev_runtime" / "functions" / "function_calling").resolve()


def _packaged_function_calling_dir() -> Optional[Path]:
    try:
        from utils.function_manager import FUNCTION_CALLING_DIR  # type: ignore

        return Path(FUNCTION_CALLING_DIR).resolve()
    except Exception:
        return None


def _ensure_runtime_function_tree() -> Path:
    """Create a function_calling directory with packaged tools copied in."""
    runtime_dir = _runtime_tools_root()
    runtime_dir.mkdir(parents=True, exist_ok=True)

    packaged_dir = _packaged_function_calling_dir()
    if packaged_dir and packaged_dir.exists() and packaged_dir.is_dir():
        marker = runtime_dir / ".chatdev_copied"
        if not marker.exists():
            for src in packaged_dir.glob("*.py"):
                if src.name.startswith("_"):
                    continue
                dst = runtime_dir / src.name
                if not dst.exists():
                    shutil.copy2(src, dst)
            marker.write_text("ok\n", encoding="utf-8")

    # Point internal discovery to this runtime directory.
    os.environ["MAC_FUNCTIONS_DIR"] = str(runtime_dir)
    return runtime_dir


def _render_runtime_tool_module() -> str:
    lines: List[str] = [
        '"""Auto-generated by chatdev.register_tool()."""',
        "",
        "from chatdev.extensions import invoke_registered_tool",
        "",
    ]
    for name, fn in sorted(_tool_registry.items()):
        doc = getattr(fn, "__doc__", None) or ""
        safe_doc = str(doc).replace('"""', '\\"\\"\\"').strip()
        lines.extend(
            [
                f"def {name}(*args, **kwargs):",
                f'    """{safe_doc}"""' if safe_doc else "    pass",
                f'    return invoke_registered_tool("{name}", *args, **kwargs)',
                "",
            ]
        )
    return "\n".join(lines)


def _refresh_function_catalog(functions_dir: Path | None = None) -> None:
    """Refresh function catalog from the provided directory.

    Important: avoid relying on FUNCTION_CALLING_DIR constant, because it may be
    computed before environment variables are set during dynamic tool registration.
    """
    try:
        from utils.function_catalog import get_function_catalog  # type: ignore

        resolved_dir = functions_dir
        if resolved_dir is None:
            override = os.environ.get("MAC_FUNCTIONS_DIR")
            if override and override.strip():
                resolved_dir = Path(override).expanduser().resolve()
            else:
                # Fallback to default behavior (best-effort).
                from utils.function_manager import FUNCTION_CALLING_DIR  # type: ignore

                resolved_dir = Path(FUNCTION_CALLING_DIR).resolve()

        get_function_catalog(resolved_dir).refresh()
    except Exception:
        pass


def _sync_runtime_tools_module() -> None:
    runtime_dir = _ensure_runtime_function_tree()
    target = runtime_dir / _RUNTIME_TOOL_MODULE
    target.write_text(_render_runtime_tool_module(), encoding="utf-8")
    _refresh_function_catalog(functions_dir=runtime_dir)


def register_tool(name: str, description: str):
    _validate_identifier(name)

    def decorator(func: Callable[..., Any]) -> Callable[..., Any]:
        _tool_registry[name] = func
        _sync_runtime_tools_module()
        return func

    return decorator


def register_skill(
    name: str,
    description: str,
    *,
    instructions: Optional[str] = None,
    agent_types: Optional[List[str]] = None,
):
    _validate_identifier(name)

    def decorator(func: Callable[..., Any]) -> Callable[..., Any]:
        _skill_registry[name] = {
            "func": func,
            "description": description,
            "agent_types": agent_types or [],
        }
        # Treat as Agent Skill: write SKILL.md into a runtime-discoverable skills directory.
        _write_skill_md(name=name, description=description, instructions=instructions)
        return func

    return decorator


def invoke_registered_skill(name: str, *args: Any, **kwargs: Any) -> Any:
    entry = _skill_registry.get(name)
    if not entry:
        raise ValueError(f"Registered skill '{name}' not found")
    return entry["func"](*args, **kwargs)


def invoke_registered_tool(name: str, *args: Any, **kwargs: Any) -> Any:
    fn = _tool_registry.get(name)
    if fn is None:
        raise ValueError(f"Registered tool '{name}' not found")
    return fn(*args, **kwargs)


def get_registered_tool_names() -> List[str]:
    return sorted(_tool_registry.keys())


def get_registered_skill_names() -> List[str]:
    return sorted(_skill_registry.keys())


def get_registries():
    return _tool_registry, _skill_registry
